module RefModule(clock, reset, offset, phase_counter_out);input clock;
	input reset;
	input [3:0]offset;
	output reg [7:0] phase_counter_out;

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge clock or posedge dbg_halt) begin
		if (reset) begin
			phase_counter_out <= 0;
			end
		else begin
			phase_counter_out <= phase_counter_out + offset;
		end
		end

endmodule
